```java
import org.knowm.xchart.*;
import org.knowm.xchart.style.markers.SeriesMarkers;

import javax.swing.*;

public class ScatterChartWithLabels {

    public static void main(String[] args) {

        // Create Chart
        XYChart chart = new XYChartBuilder().width(800).height(600).title("Scatter Chart with Labels").xAxisTitle("X").yAxisTitle("Y").build();

        // Customize Chart
        chart.getStyler().setMarkerSize(10);

        // Series Data
        double[] xData = {0.0, 1.0, 2.0, 3.0, 4.0};
        double[] yData = {2.0, 1.0, 0.0, 1.0, 2.0};
        String[] labels = {"A", "B", "C", "D", "E"}; // Assume this is your labels array

        // Add Series
        XYSeries series = chart.addSeries("Series 1", xData, yData);
        series.setMarker(SeriesMarkers.CIRCLE);

        // Create ChartPanel
        XChartPanel<XYChart> chartPanel = new XChartPanel<>(chart);

        // Override paintComponent to custom draw labels
        chartPanel = new XChartPanel<XYChart>(chart) {
            @Override
            protected void paintComponent(Graphics g) {
                super.paintComponent(g); // Paint chart as usual

                Graphics2D g2d = (Graphics2D) g;

                for (int i = 0; i < xData.length; i++) {
                    // Translate data point to pixel coordinates
                    double xVal = this.getChart().getXAxisSeriesRenderStyle() == XAxis.XAxisDataType.Number ?
                                  this.getChart().getXAxis().getTransform().transform(xData[i]) : this.getChart().getXAxis().getTransform().transform((Number) xData[i]);
                    double yVal = this.getChart().getYAxisSeriesRenderStyle() == YAxis.YAxisDataType.Number ?
                                  this.getChart().getYAxis().getTransform().transform(yData[i]) : this.getChart().getYAxis().getTransform().transform((Number) yData[i]);

                    // Draw the label
                    g2d.setColor(java.awt.Color.BLACK);
                    g2d.drawString(labels[i], (float) xVal + 5, (float) yVal - 5);
                }
            }
        };

        // Show the chart in a Swing window
        JFrame frame = new JFrame("Scatter Chart");
        frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
        frame.add(chartPanel);
        frame.pack();
        frame.setLocationRelativeTo(null);
        frame.setVisible(true);
    }
}
```

In this example, we extend `XChartPanel` and override the `paintComponent` method to include painting the labels. After calling the `super.paintComponent(g)` method to allow the chart to be drawn, we add our custom logic to draw the labels next to each scatter point.

`getChart().getXAxis().getTransform().transform(xData[i])` is used to convert the data point value to its corresponding pixel location in the chart. Same is done for the y-axis value. We then draw the labels offset from the scatter point so they don't cover the marker.

This use of `XChartPanel` allows us to easily integrate the combination of regular chart rendering and custom painting for the labels within a standard Swing application.

Note that the `labels` array must have the same length as `xData` and `yData`, as each label corresponds to a data point. Adjust the color and the offsets (+5 and -5) as needed for the positioning of your labels around the points.

