```java
import org.jfree.chart.ChartFactory;
import org.jfree.chart.ChartUtils;
import org.jfree.chart.JFreeChart;
import org.jfree.chart.plot.PlotOrientation;
import org.jfree.chart.plot.XYPlot;
import org.jfree.data.xy.XYDataset;
import org.jfree.data.xy.XYSeries;
import org.jfree.data.xy.XYSeriesCollection;

import java.awt.*;
import java.io.File;
import java.io.IOException;

public class ScatterPlotExample {
    public static void main(String[] args) throws IOException {
        // 创建数据集
        XYDataset dataset = createDataset();

        // 创建散点图
        JFreeChart chart = ChartFactory.createScatterPlot(
                "Scatter Plot Example", // 图表标题
                "X-Axis", // x轴标题
                "Y-Axis", // y轴标题
                dataset, // 数据集
                PlotOrientation.VERTICAL, // 绘图方向
                true, // 显示图例
                false, // 不生成工具
                false // 不生成URL链接
        );

        // 自定义渲染
        XYPlot plot = (XYPlot) chart.getPlot();
        plot.setRenderer(new XYDotRendererCustom());

        // 保存为PNG
        ChartUtils.saveChartAsPNG(new File("scatter_plot.png"), chart, 800, 600);
    }

    private static XYDataset createDataset() {
        XYSeries series = new XYSeries("Series");

        // 假设的散点数据
        series.add(1.0, 4.0);
        series.add(2.0, 5.0);
        series.add(3.0, 3.0);
        series.add(4.0, 5.0);
        series.add(5.0, 4.0);

        XYSeriesCollection dataset = new XYSeriesCollection();
        dataset.addSeries(series);

        return dataset;
    }

    // 自定义渲染器，用于设置散点点的大小和颜色
    private static class XYDotRendererCustom extends org.jfree.chart.renderer.xy.XYDotRenderer {
        @Override
        public void drawItem(Graphics2D g2, org.jfree.chart.renderer.xy.XYItemRendererState state,
                             Rectangle2D dataArea, PlotRenderingInfo info, XYPlot plot,
                             ValueAxis domainAxis, ValueAxis rangeAxis, XYDataset dataset,
                             int series, int item, CrosshairState crosshairState, int pass) {

            // 使用自定义的颜色和点大小
            g2.setPaint(Color.BLUE);
            int dotWidth = 12; // 点的宽度（直径）
            int dotHeight = 12; // 点的高度（直径）

            // 获取该数据点的X和Y值，并转换为屏幕坐标
            double x = dataset.getXValue(series, item);
            double y = dataset.getYValue(series, item);
            double transX = domainAxis.valueToJava2D(x, dataArea, plot.getDomainAxisEdge());
            double transY = rangeAxis.valueToJava2D(y, dataArea, plot.getRangeAxisEdge());

            // 绘制散点
            Ellipse2D dot = new Ellipse2D.Double(transX - dotWidth / 2.0, transY - dotHeight / 2.0, dotWidth, dotHeight);
            g2.fill(dot);
        }
    }
}
```

