```java
import javafx.application.Application;
import javafx.embed.swing.SwingFXUtils;
import javafx.scene.Scene;
import javafx.scene.chart.NumberAxis;
import javafx.scene.chart.ScatterChart;
import javafx.scene.chart.XYChart;
import javafx.scene.control.Label;
import javafx.scene.layout.StackPane;
import javafx.scene.paint.Color;
import javafx.stage.Stage;

import javax.imageio.ImageIO;
import java.awt.image.BufferedImage;
import java.io.File;
import java.io.IOException;

public class JavaFXScatterChartWithLabels extends Application {

    @Override
    public void start(Stage stage) throws IOException {
        // 创建散点图
        NumberAxis xAxis = new NumberAxis();
        NumberAxis yAxis = new NumberAxis();
        ScatterChart<Number, Number> scatterChart = new ScatterChart<>(xAxis, yAxis);
        scatterChart.setTitle("Custom Scatter Chart");

        // 数据系列和数据点
        XYChart.Series<Number, Number> series = new XYChart.Series<>();
        series.setName("Data Series");

        // 创建数据点，自定义标签和颜色
        XYChart.Data<Number, Number> dataPoint1 = new XYChart.Data<>(1, 3);
        XYChart.Data<Number, Number> dataPoint2 = new XYChart.Data<>(2, 7);
        XYChart.Data<Number, Number> dataPoint3 = new XYChart.Data<>(3, 2);

        // 把数据点添加到系列中
        series.getData().addAll(dataPoint1, dataPoint2, dataPoint3);

        // 把系列添加到图表中
        scatterChart.getData().add(series);

        // 对每个数据点应用自定义配置
        for (XYChart.Data<Number, Number> data : series.getData()) {
            // 创建标签并设置颜色
            StackPane node = new StackPane(new Label("Label " + data.getXValue()));
            node.setStyle("-fx-background-color: " + getColorCodeByData(data.getYValue().doubleValue()) + "; -fx-background-radius: 5px;");
            data.setNode(node);
        }

        // 创建场景并显示
        Scene scene = new Scene(scatterChart, 600, 400);
        stage.setScene(scene);
        stage.show();

        // 保存为图片
        saveChartAsImage(scatterChart);
    }

    private String getColorCodeByData(double value) {
        if (value < 3) {
            return "red";
        } else if (value < 6) {
            return "green";
        } else {
            return "blue";
        }
    }

    private void saveChartAsImage(ScatterChart<Number, Number> chart) throws IOException {
        Scene scene = chart.getScene();
        if (scene != null) {
            // Take a snapshot of the chart
            WritableImage image = scene.snapshot(null);

            // Convert to a BufferedImage
            BufferedImage bufferedImage = SwingFXUtils.fromFXImage(image, null);

            // Write the image to a file
            File outputFile = new File("chart.png");
            ImageIO.write(bufferedImage, "png", outputFile);

            System.out.println("Chart has been saved to: " + outputFile.getAbsolutePath());
        }
    }

    public static void main(String[] args) {
        launch(args);
    }
}
```

在这个例子中：

- 使用`ScatterChart`，将创建一个带有数轴（NumberAxis）的散点图。
- 添加一个数据系列和几个数据点到这个系列。
- 自定义每个数据点，使用颜色和标签通过设置节点的样式。
- 在应用启动后，将图表保存为PNG文件。

图表保存部分使用 `Scene.snapshot()` 方法来获取散点图的快照，并使用 `ImageIO.write` 方法将图像保存为文件。确保你的应用运行中没有抛出异常，否则可能需要适当的异常处理。

